    def keyPressEvent(self, event):
        # 这里event.key（）显示的是按键的编码
        print("按下：" + str(event.key()))
        # 举例，这里Qt.Key_A注意虽然字母大写，但按键事件对大小写不敏感
        fileName = datetime.datetime.now().strftime('%Y-%m-%d-%H-%M-%S')
        if event.key() == Qt.Key_1:
            print('截取屏幕1图片，结果保存至' + str(self.result_path) + '文件夹')
            pixmap = self.label_layout1.pixmap().copy()
            if pixmap is not None:
                qImg = pixmap.toImage()
                qImg.save(self.result_path + "/" + "Screenshot" + str(fileName) + ".bmp", "BMP", 100)
            else:
                print("屏幕1未识别到图片！！")
        if event.key() == Qt.Key_2:
            print('截取屏幕2图片，结果保存至' + str(self.result_path) + '文件夹')
            pixmap = self.label_layout2.pixmap().copy()
            if pixmap is not None:
                qImg = pixmap.toImage()
                qImg.save(self.result_path + "/" + "Screenshot" + str(fileName) + ".bmp", "BMP", 100)
            else:
                print("屏幕2未识别到图片！！")
        if event.key() == Qt.Key_3:
            print('截取屏幕3图片，结果保存至' + str(self.result_path) + '文件夹')
            pixmap = self.label_layout3.pixmap().copy()
            if pixmap is not None:
                qImg = pixmap.toImage()
                qImg.save(self.result_path + "/" + "Screenshot" + str(fileName) + ".bmp", "BMP", 100)
            else:
                print("屏幕3未识别到图片！！")
        # if event.key() == Qt.Key_4:
        #     print('截取屏幕4图片，结果保存至' + str(self.result_path) + '文件夹')
        #     pixmap = self.label_layout4.pixmap().copy()
        #     if pixmap is not None:
