        # 当需要组合键时，要很多种方式，这里举例为“shift+单个按键”，也可以采用shortcut、或者pressSequence的方法。
        if event.key() == Qt.Key_P:
            if QtWidgets.QApplication.keyboardModifiers() == Qt.ShiftModifier:
                print("shift + p打开输出文件夹")
                self.show_dir()
        if event.key() == Qt.Key_R:
            if not Globals.stop_sign:
                print("程序暂停！！！")
                Globals.stop_sign = True
            else:
                print("程序继续运行！！！")
                Globals.stop_sign = False
        if event.key() == Qt.Key_Q:
            if not Globals.visible:
                print("可视化开启！！！")
                Globals.visible = True
            else:
                print("可视化关闭！！！")
                Globals.visible = False

