class CheckThread(QThread):
    signal_done = pyqtSignal(int)  # 是否结束信号

    def __init__(self, label, nDevNum):
        super(CheckThread, self).__init__()
        self.label = label
        self.nDevNum = nDevNum

    def run(self):
        checkdetect.run(source=self.nDevNum, show_label=self.label,
                        use_camera=True)
        self.signal_done.emit(1)  # 发送结束信号
